(function() {
    var examAdditionalNoteController = function($scope, $http, $rootScope,$ocLazyLoad,$modal, $timeout,$modalInstance,examAdditionalNoteService,initData) {
        $scope.additionalNotes = undefined;
        $scope.selectedTab = 1;
        $scope.guidanceImage = {
            notesImage:'data:image/jpg;base64,',
            observationImage:'data:image/jpg;base64,',
            showNotesImage:false,
            showObservationsImage:false,
        }

        var isConcurEnabled = false;

        $scope.initExamAdditionalNote = function() {
            $scope.patientId = initData.patientId;
            $scope.encounterId = initData.encounterId;
            $scope.isThumbnailVisible = getItemKeyValue("ShowThumbNailsInProgressNotes").toLowerCase()==="yes";
            isConcurEnabled = getItemKeyValue("EnableConcurLock");
            if(isConcurEnabled.toLowerCase() === "yes") {
                isConcurEnabled = true;
            }else {
                isConcurEnabled = false;
            }
            $scope.loadAdditionalData(true);
            $('#examAdditionalModal').modal();
            if (initData.client && initData.client === 'EXE'){
                $("#observationsTabs").css({"height":"230px"});
                $("#examNotesTabs").css({"height":"230px"});
                $("#examAdditional1").css({"height":"350px",left:"20px"});
                $("#examAdditional2").css({"height":"350px",left:"-100px"});
                setTimeout(function(){
                    $(".additionalNoteModal .modal-dialog").draggable({ disabled: true });
                });
            }
        };

        $scope.selectTab = function(dataSize,tabNumber){
            if(dataSize>0){
                $scope.selectedTab = tabNumber;
            }
        }

        var cloneNotesToModifiedNotes = function(){
            $scope.additionalNotes.annualNotes = [];
            for(var index in $scope.additionalNotes.notes){
                var notes = $scope.additionalNotes.notes[index];
                $scope.additionalNotes.annualNotes.push({notes:notes, modifiedNotes:notes});
            }
            $scope.additionalNotes.notes = undefined;
        }

        $scope.loadAdditionalData = function(resetTabs){
            var aPromise = examAdditionalNoteService.getCategoryDetails(initData.encounterId, 0);
            aPromise.then(function(object) {
                $scope.additionalNotes = {notes:[],observations:[],annualNotes:[]};
                var x2js = new X2JS();
                var json = x2js.xml_str2json(object);
                var addNotes = json.Envelope.Body.return.additionalnotes;
                if(addNotes){
                    if(addNotes.notes){
                        $scope.additionalNotes.notes = $scope.returnArray(addNotes.notes.notes);
                        cloneNotesToModifiedNotes();
                    }
                    if(addNotes.observations){
                        $scope.additionalNotes.observations = $scope.returnArray(addNotes.observations.observation);
                        for(var index in $scope.additionalNotes.observations){
                            $scope.additionalNotes.observations[index].suggestedcategories = $scope.returnArray($scope.additionalNotes.observations[index].suggestedcategories.suggestedcategory);
                            $scope.additionalNotes.observations[index].enableCopyBtn = false;
                            $scope.additionalNotes.observations[index].enableMergeBtn = false;
                            if($scope.additionalNotes.observations[index].suggestedcategories.length>0){
                                $scope.additionalNotes.observations[index].suggestedCategoryId = $scope.additionalNotes.observations[index].suggestedcategories[0].suggestedCategoryId;
                                $scope.additionalNotes.observations[index].enableCopyBtn = true;
                                $scope.additionalNotes.observations[index].enableMergeBtn = true;
                                if($scope.additionalNotes.observations[index].struct === '1' ){
                                    if($scope.additionalNotes.observations[index].eligibleforcopy !== '1'){
                                        $scope.additionalNotes.observations[index].enableCopyBtn = false;
                                    }
                                    $scope.additionalNotes.observations[index].enableMergeBtn = false;
                                }
                            }
                        }
                    }
                }
                if(resetTabs) {
                    if ($scope.additionalNotes.observations.length > 0) {
                        $scope.selectedTab = 1;
                    } else if ($scope.additionalNotes.annualNotes.length > 0) {
                        $scope.selectedTab = 2;
                    }
                }
            });
        }

        $scope.returnArray = function(data){
            var response = [];
            if(Array.isArray(data)){
                response = data;
            }else{
                response.push(data);
            }
            return response;
        }

        $scope.close = function(){
            $modalInstance.close('success');
            if (initData.client && initData.client === 'EXE'){
                closeVbFrmWeb();
                $scope.$destroy();
            }
        }

        $scope.openCategoryTree = function(annualNotes) {
            var initModalData = {
                section: "examination",
                client: initData.client
            };

            var modalUrl = "/mobiledoc/jsp/webemr/templates/category-tree-tpl.html";
            $ocLazyLoad.load({
                name: "categoryTreeApp",
                files: [
                    '/mobiledoc/jsp/webemr/templates/category-tree-tpl.js',
                    '/mobiledoc/jsp/webemr/progressnotes/templates/category-search.component.js'
                ],
                cache: true
            }).then(function() {
                var modalInstance = $modal.open({
                    templateUrl: makeURL(modalUrl),
                    controller: 'categoryTreeController',
                    windowClass: 'app-modal-window bluetheme categoryTreeModal',
                    backdrop: "static",
                    resolve: {
                        initModalData: function() {
                            return initModalData;
                        }
                    }
                });

                modalInstance.result.then(function(selectedCategory) {
                    if(selectedCategory){
                        $scope.copyMergeNote(selectedCategory,annualNotes.modifiedNotes, annualNotes.notes);
                    }
                }, function(response) {
                });

            }, function(e) {
            });
        };

        $scope.copyMergeNote = function (selectedCategory,modifiedNotes, notesToBeDeleted) {
            var unmappedNoteMsg = "";
            if(selectedCategory.action === 'merge'){
                unmappedNoteMsg = "This action will merge with existing Notes. Are you sure you want to merge?";
            }else{
                unmappedNoteMsg = "This action will overwrite existing Notes. Are you sure you want to copy?";
            }
            ecwConfirm(unmappedNoteMsg, "", function() {
                if (selectedCategory.action === 'merge') {
                    $scope.saveNotesWithExistingNotes(selectedCategory.id, modifiedNotes, notesToBeDeleted);
                } else {
                    $scope.saveNotes(selectedCategory.id, modifiedNotes,notesToBeDeleted);
                }
            });
        }

        $scope.saveNotesWithExistingNotes = function (selectedCategoryId,modifiedNotes, notesToBeDeleted) {
            examAdditionalNoteService.getNotes($scope.encounterId,selectedCategoryId).then(function (object) {
                var x2js = new X2JS();
                var notejson = x2js.xml_str2json(object);
                if (notejson.Envelope.Body.return.encounter !== undefined) {
                    modifiedNotes = notejson.Envelope.Body.return.encounter.notes + ", " + modifiedNotes;
                }
                $scope.saveNotes(selectedCategoryId,modifiedNotes,notesToBeDeleted);
            });
        }

        var saveNotesXML = function(selectedCategoryId,notes){
            var xw = new XMLWriter('ISO-8859-1', '1.0');
            startSoapPacket(xw);
            xw.writeStartElement('encounter');
            xw.writeAttributeString('xsi:type', 'xsd:string');
            addElement(xw, 'encId', $scope.encounterId, 'xsi:type', 'xsd:string');
            addElement(xw, 'catId', selectedCategoryId, 'xsi:type', 'xsd:string');
            addElement(xw, 'notes', "<![CDATA[" + replaceUTFCharWithASCII(notes) + "]]>", 'xsi:type', 'xsd:string');
            addElement(xw, 'type', 'E', 'xsi:type', 'xsd:string');
            xw.writeEndElement();
            endSoapPacket(xw);
            return xw.flush();
        }

        $scope.saveNotes = function(selectedCategoryId,modifiedNotes,notesToBeDeleted) {
            if(isConcurEnabled){
                examAdditionalNoteService.checkConcurrency($scope.encounterId).then(function (object) {
                    if(object && object.status === 'success'){
                        saveNotesCallBack(selectedCategoryId, modifiedNotes, examAdditionalNoteService, $scope, notesToBeDeleted);
                    }else if(object && object.status === 'failed'){
                        ecwAlert(object.message);
                    }
                }, function errorCallback(error) {
                    ecwAlert("Some Error occurred while checking concurrency.Please try again later");
                });
            } else{
                saveNotesCallBack(selectedCategoryId, modifiedNotes, examAdditionalNoteService, $scope, notesToBeDeleted);
            }
        }

        function saveNotesCallBack(selectedCategoryId, modifiedNotes, examAdditionalNoteService, $scope, notesToBeDeleted) {
            var xmlData = saveNotesXML(selectedCategoryId, modifiedNotes);
            examAdditionalNoteService.saveNotes($scope.encounterId, selectedCategoryId, xmlData).then(function (object) {
                examAdditionalNoteService.deleteNote($scope.encounterId, 'E', btoa(notesToBeDeleted)).then(function (response) {
                    $scope.loadAdditionalData(false);
                });
            }, function errorCallback(error) {
                ecwAlert("Some Error occurred while coping/merging unmapped data.Please try again later");
            });
        }

        $scope.saveObservation = function(observation,isCopy){
            var msg = ""
            if(isCopy){
                msg = "This action will overwrite any existing information currently"
                    + " documented in the suggested Observation. Are you sure"
                    + " you"
                    + " want to copy this Note?";
            }else{
                msg = "This action will merge with existing information currently"
                    + " documented in the suggested Observation. Are you sure you"
                    + " want to merge this Note? ";
            }
            ecwConfirm(msg, "", function() {
                if(isConcurEnabled){
                    examAdditionalNoteService.checkConcurrency($scope.encounterId).then(function (object) {
                        if(object && object.status === 'success'){
                            saveObservationCallback(observation, isCopy);
                        }else if(object && object.status === 'failed'){
                            ecwAlert(object.message);
                        }
                    }, function errorCallback(error) {
                        ecwAlert("Some Error occurred while checking concurrency.Please try again later");
                    });
                } else{
                    saveObservationCallback(observation, isCopy);
                }
            });
        }

        function saveStructNotes(observation){
            examAdditionalNoteService.saveStructNotes($scope.encounterId, observation.suggestedCategoryId, observation.propId).then(function (object) {
            }, function errorCallback(error) {
                ecwAlert("Some Error occurred while deleting unmapped data.Please try again later");
            });
        }

        function saveDocument(observation){
            examAdditionalNoteService.saveDocument($scope.encounterId, observation.suggestedCategoryId, observation.propId).then(function (object) {
            }, function errorCallback(error) {
                ecwAlert("Some Error occurred while deleting unmapped data.Please try again later");
            });
        }

        function saveObservationCallback(observation, isCopy) {
            examAdditionalNoteService.saveObservation($scope.encounterId, observation.suggestedCategoryId, getSaveObservationJson(observation), isCopy).then(function (object) {
                if(observation.struct === '1'){
                    saveStructNotes(observation);
                }
                if(observation.attachment === '1'){
                    saveDocument(observation);
                }
                examAdditionalNoteService.deleteObservation(getDeleteObservationJson(observation)).then(function (response) {
                    $scope.loadAdditionalData();
                });
            }, function errorCallback(error) {
                ecwAlert("Some Error occurred while coping/merging unmapped data.Please try again later");
            });
        }

        var getSaveObservationJson = function(observation){
            return {"encounterId":$scope.encounterId,"id":observation.id,"examCategoryId":observation.suggestedCategoryId,"propId":observation.propId, "notes":replaceUTFCharWithASCII(observation.notes), "notes2":observation.notes2};
        }

        var getDeleteObservationJson = function(observation){
            return {"encounterId":$scope.encounterId,"id":observation.id,"propId":observation.propId};
        }

        $scope.deleteObservation = function(observation){
            ecwConfirm("Are you sure you want to delete the note?", "", function() {
                examAdditionalNoteService.deleteObservation(getDeleteObservationJson(observation)).then(function (response) {
                    $scope.loadAdditionalData();
                }, function errorCallback(error) {
                    ecwAlert("Some Error occurred while deleting unmapped data.Please try again later");
                });
            });
        }

        $scope.deleteNote = function(note){
            ecwConfirm("Are you sure you want to delete the note?", "", function() {
                examAdditionalNoteService.deleteNote($scope.encounterId, 'E', btoa(note)).then(function (response) {
                    $scope.loadAdditionalData();
                }, function errorCallback(error) {
                    ecwAlert("Some Error occurred while deleting unmapped data.Please try again later");
                });
            });
        }

        $scope.showObservationNotes = function(notes){
            $scope.currentObservationNotes = notes;
            if($scope.currentObservationNotes) {
                $("#additionalObservationNotesModal").modal({backdrop: "static", keyboard: false});
            }
        };

    }
    var examAdditionalNoteService = function($http) {
        return {
            checkConcurrency: function (encounterId) {
                var serverUrl = '/mobiledoc/emr/concurrency/check/frmExam/'+encounterId+"/0";
                serverUrl = makeURL(serverUrl);
                var aPromise = $http.get(serverUrl).then(function (response) {
                    return response.data;
                }, function (response) {
                    throw "Internal Error occured, Please try after some time";
                });
                return aPromise;
            },
            getCategoryDetails: function (encounterId, examinationid) {
                var url = '/mobiledoc/jsp/catalog/xml/getExamination.jsp?EncounterId=' + encounterId + '&ExaminationId=' + examinationid;
                url = makeURL(url);
                var aPromise = $http.get(url).then(function (response) {
                    return response.data;
                }, function (response) {
                    throw "Internal Error occured, Please try after some time";
                });
                return aPromise;
            },
            getNotes: function (encounterId, examinationId) {
                var url = '/mobiledoc/jsp/catalog/xml/getNotes.jsp?encounterId=' + encounterId + '&catId=' + examinationId;
                url = makeURL(url);
                var aPromise = $http.get(url).then(function (response) {
                    return response.data;
                }, function (response) {
                    throw "Internal Error occured, Please try after some time";
                });
                return aPromise;
            },
            saveNotes: function (encounterId, examinationId, xmlData) {
                var url = '/mobiledoc/jsp/catalog/xml/setNotes.jsp?encounterId=' + encounterId + '&catId=' + examinationId + '&source=UnmappedNotes';
                url = makeURL(url);
                var xsrf = $.param({FormData: xmlData});
                var aPromise = $http({
                    headers: {'Content-Type': 'application/x-www-form-urlencoded'},
                    dataType: 'text',
                    method: 'POST',
                    url: url,
                    data: xsrf
                }).then(function (response) {
                    return response.data;
                }, function (response) {
                    throw "Internal Error occured, Please try after some time";
                });
                return aPromise;
            },
            saveObservation: function (encounterId, examinationId, requestBody,isCopy) {
                var serverUrl = '/mobiledoc/clinicaldocumentation/examination/unmapped/items/false';
                if(isCopy === 0){
                    serverUrl = '/mobiledoc/clinicaldocumentation/examination/unmapped/items/true';
                }
                serverUrl = makeURL(serverUrl);
                var aPromise = $http({
                    headers: {'Content-Type': 'application/json'},
                    dataType: 'text',
                    method: 'POST',
                    url: serverUrl,
                    data: requestBody
                }).then(function(response) {
                    return  response.data;
                }, function(response) {
                    throw "Internal Error occured, Please try after some time";
                });
                return aPromise;
            },
            saveStructNotes: function (encounterId,catId,itemId) {
                var serverUrl = '/mobiledoc/emr/structdata/question/unmapped/items/struct/2/'+encounterId+'/'+catId+'/'+itemId;
                serverUrl = makeURL(serverUrl);
                var aPromise = $http({
                    headers: {'Content-Type': 'application/x-www-form-urlencoded'},
                    dataType: 'text',
                    method: 'POST',
                    url: serverUrl
                }).then(function(response) {
                    return  response.data;
                }, function(response) {
                    throw "Internal Error occured, Please try after some time";
                });
                return aPromise;
            },
            saveDocument: function (encounterId,catId,itemId) {
                var serverUrl = '/mobiledoc/emr/progressnotes/documents/unmapped/items/document/'+encounterId+'/'+catId+'/'+itemId;
                serverUrl = makeURL(serverUrl);
                var xsrf = {};
                var aPromise = $http({
                    headers: {'Content-Type': 'application/x-www-form-urlencoded'},
                    dataType: 'text',
                    method: 'POST',
                    url: serverUrl,
                    data: xsrf
                }).then(function(response) {
                    return  response.data;
                }, function(response) {
                    throw "Internal Error occured, Please try after some time";
                });
                return aPromise;
            },
            deleteObservation: function (requestBody) {
                var serverUrl = '/mobiledoc/clinicaldocumentation/examination/unmapped/observation/'
                serverUrl = makeURL(serverUrl);
                var aPromise = $http({
                    headers: {'Content-Type': 'application/json'},
                    dataType: 'text',
                    method: 'POST',
                    url: serverUrl,
                    data: requestBody
                }).then(function(response) {
                    return  response.data;
                }, function(response) {
                    throw "Internal Error occured, Please try after some time";
                });
                return aPromise;
            },
            deleteNote: function (encounterId,type,notes) {
                var serverUrl = '/mobiledoc/clinicaldocumentation/examination/unmapped/notes/'+encounterId+'/'+type;
                serverUrl = makeURL(serverUrl);
                var requestBody = {"notes": notes};
                var aPromise = $http({
                    headers: {'Content-Type': 'application/json'},
                    dataType: 'text',
                    method: 'POST',
                    url: serverUrl,
                    data: requestBody
                }).then(function(response) {
                    return  response.data;
                }, function(response) {
                    throw "Internal Error occured, Please try after some time";
                });
                return aPromise;
            }
        }
    }
    var examAdditionalNoteApp = angular.module("examAdditionalNoteApp", ['ui.bootstrap','oc.lazyLoad']);
    examAdditionalNoteApp.controller("examAdditionalNoteController", examAdditionalNoteController);
    examAdditionalNoteApp.service('examAdditionalNoteService', examAdditionalNoteService);
})();